/// <summary>
/// Selects an appropriate report to execute and executes it.
/// </summary>
/// <param name="_args">
/// An instance of the <c>Args</c> class.
/// </param>
public void execute(Args _args)
{
    if (BrazilParameters::isEnabled())
    {
        this.parmReportName(ssrsReportStr(ETGVendAccountStatementInt, ReportBR));
    }
    else
    {
        this.parmReportName(ssrsReportStr(ETGVendAccountStatementInt, Report));
    }

    this.parmArgs(_args);
    this.startOperation();
}
